"use strict";(globalThis.webpackChunkeo_glossary=globalThis.webpackChunkeo_glossary||[]).push([[5196],{24438(e){e.exports=JSON.parse('{"tag":{"label":"to be approved","permalink":"/eo-glossary/tags/to-be-approved","allTagsPath":"/eo-glossary/tags","count":106,"items":[{"id":"terms/accuracy","title":"Accuracy","description":"Proximity of Measurement results to the accepted Value; precision is the degree to which repeated or reproducible measurements under unchanged conditions show the same results.","permalink":"/eo-glossary/terms/accuracy"},{"id":"terms/ancillary_data","title":"Ancillary Data","description":"Data acquired on the same platform but not obtained from the main Sensor itself (usually provided as part of Level 0 Data), with the primary purpose of serving the processing of main instrument Data.","permalink":"/eo-glossary/terms/ancillary_data"},{"id":"terms/anthroposphere","title":"Anthroposphere","description":"One of the Earth spheres consisting predominantly of matter processed by humans, such as construction wood, bricks, concrete, asphalt, glass, or plastics.","permalink":"/eo-glossary/terms/anthroposphere"},{"id":"terms/archive","title":"Archive","description":"System that stores data products, guaranteeing their preservation for future use, including all operations to identify, store and retrieve the data and ensure their integrity.","permalink":"/eo-glossary/terms/archive"},{"id":"terms/area_of_interest","title":"Area of Interest","description":"Zone in 2D or 3D for which Information or Data is requested. It can be discontinuous in space, consisting of the union of many separate zones.","permalink":"/eo-glossary/terms/area_of_interest"},{"id":"terms/atmosphere","title":"Atmosphere","description":"Layer of gases, commonly known as air, including suspended liquid and solid particles known as aerosols (incl. dust, clouds, snow and ice).","permalink":"/eo-glossary/terms/atmosphere"},{"id":"terms/auxiliary_data","title":"Auxiliary Data","description":"Data that enhance the processing and utilisation of main Sensor Data, usually not captured by the same Data collection Process or on the same platform as the main Sensor Data.","permalink":"/eo-glossary/terms/auxiliary_data"},{"id":"terms/backup","title":"Backup","description":"General practice of making copies of current baseline and derived products of EO Collections at specified time intervals, storing those copies in a manner that will not affect the data if the primary distribution environment is compromised.","permalink":"/eo-glossary/terms/backup"},{"id":"terms/band_central_wavelength","title":"Band Central Wavelength","description":"Single wavelength Value within the sensitivity interval of a spectroradiometric Sensor which represents the respective band. It could be the mean, median, maximum sensitivity, or any other reasonable representative Value.","permalink":"/eo-glossary/terms/band_central_wavelength"},{"id":"terms/baseline","title":"Baseline","description":"Reference Period, time or measure against which Information is assessed or compared.","permalink":"/eo-glossary/terms/baseline"},{"id":"terms/biosphere","title":"Biosphere","description":"Masses of living organisms, such as vegetation and animals, including dead but still connected parts such as roots, trunks or branches.","permalink":"/eo-glossary/terms/biosphere"},{"id":"terms/business_continuity","title":"Business Continuity","description":"An organisation\'s readiness to continue functioning during times of disruption.","permalink":"/eo-glossary/terms/business_continuity"},{"id":"terms/catalogue","title":"Catalogue","description":"System that provides users with discovery of information on which EO products can be obtained.","permalink":"/eo-glossary/terms/catalogue"},{"id":"terms/cell","title":"Cell","description":"Spatial, spatio-temporal zone or temporal unit of geometry with dimensionality greater than 0, associated with a zone.","permalink":"/eo-glossary/terms/cell"},{"id":"terms/classification_system","title":"Classification System","description":"Nomenclature used to classify Information into categorical thematic classes (e.g., EUNIS, MAES ecosystems, Corine Land Cover, LCCS).","permalink":"/eo-glossary/terms/classification_system"},{"id":"terms/climate_projection","title":"Climate Projection","description":"Simulated response of the climate system to a scenario of future emission or concentration of greenhouse gases (GHGs) and aerosols, generally derived using climate models.","permalink":"/eo-glossary/terms/climate_projection"},{"id":"terms/collection","title":"Collection","description":"Group of products that have been processed using a consistent radiometric calibration, geometric registration base, data/metadata format, and version of processing algorithms.","permalink":"/eo-glossary/terms/collection"},{"id":"terms/collection_update","title":"Collection Update","description":"Minor revisions to a relatively small number of products within a collection for the purpose of correcting errors and maintaining consistent quality.","permalink":"/eo-glossary/terms/collection_update"},{"id":"terms/collection_upgrade","title":"Collection Upgrade","description":"New and improved major version of all products within a collection due to comprehensive reprocessing.","permalink":"/eo-glossary/terms/collection_upgrade"},{"id":"terms/confidence_interval","title":"Confidence Interval","description":"Probability that a Quantity lies in a given interval, conditioned on the measuring or modelling assumptions.","permalink":"/eo-glossary/terms/confidence_interval"},{"id":"terms/coverage_interval","title":"Coverage Interval","description":"Range or specific subset of values associated with a coverage dataset.","permalink":"/eo-glossary/terms/coverage_interval"},{"id":"terms/cryosphere","title":"Cryosphere","description":"Masses of frozen water, such as sea ice, ice shields, glaciers, and snow.","permalink":"/eo-glossary/terms/cryosphere"},{"id":"terms/custodian","title":"Custodian","description":"Entity responsible for the safe custody, transport, storage of the data and implementation of business rules.","permalink":"/eo-glossary/terms/custodian"},{"id":"terms/data","title":"Data","description":"Value and possibly Uncertainty of a Trait of a specific Entity.","permalink":"/eo-glossary/terms/data"},{"id":"terms/data_format","title":"Data Format","description":"Structured Data that is machine readable and can be automatically read and processed by a computer, such as HDF, NetCDF, CSV, JSON, XML, etc.","permalink":"/eo-glossary/terms/data_format"},{"id":"terms/data_licencing","title":"Data Licencing","description":"Legal instrument by which a copyright holder may grant rights over the protected work.","permalink":"/eo-glossary/terms/data_licencing"},{"id":"terms/decommissioned_product","title":"Decommissioned Product","description":"Products and collections that have been superseded by new versions and are no longer available.","permalink":"/eo-glossary/terms/decommissioned_product"},{"id":"terms/deprecated_product","title":"Deprecated Product","description":"Products and collections that have been superseded by a newer version and are still available, but whose use is discouraged since they will be decommissioned in the future.","permalink":"/eo-glossary/terms/deprecated_product"},{"id":"terms/derivative_product","title":"Derivative Product","description":"Product additionally processed from baseline or unenhanced mission data.","permalink":"/eo-glossary/terms/derivative_product"},{"id":"terms/dispose","title":"Dispose","description":"Action of permanently and irrecoverably removing all copies of data held by an organization.","permalink":"/eo-glossary/terms/dispose"},{"id":"terms/duration","title":"Duration","description":"Non-negative interval Quantity of time equal to the difference between the final and initial instants of a time interval.","permalink":"/eo-glossary/terms/duration"},{"id":"terms/dwell_time","title":"Dwell Time","description":"Time that an antenna beam spends on a target.","permalink":"/eo-glossary/terms/dwell_time"},{"id":"terms/earth_observation_based_output","title":"Earth Observation Based Output","description":"Higher-level processing and integration output (indicative level 4 and beyond) that goes beyond basic data processing, often designed for policy or decision-making needs.","permalink":"/eo-glossary/terms/earth_observation_based_output"},{"id":"terms/earth_observation_product","title":"Earth Observation Product","description":"Direct output from standardized satellite data processing chains (indicative levels 2 and 3), representing fundamental geophysical and biophysical variables.","permalink":"/eo-glossary/terms/earth_observation_product"},{"id":"terms/earth_spheres","title":"Earth Spheres","description":"Spheres dividing planet Earth into subsystems, which are collectives of (physical) matter sharing specific traits.","permalink":"/eo-glossary/terms/earth_spheres"},{"id":"terms/entity","title":"Entity","description":"Something that has separate and distinct existence and objective or conceptual reality.","permalink":"/eo-glossary/terms/entity"},{"id":"terms/eo_space_data","title":"EO Space Data","description":"Earth Observation data generated by spaceborne missions or instruments owned by public or private organizations.","permalink":"/eo-glossary/terms/eo_space_data"},{"id":"terms/expanded_uncertainty","title":"Expanded Uncertainty","description":"Standard Uncertainty multiplied by a coverage factor k, chosen to obtain a desired level of confidence.","permalink":"/eo-glossary/terms/expanded_uncertainty"},{"id":"terms/final_product_version","title":"Final Product Version","description":"Product within an EO Collection that is not expected to be updated.","permalink":"/eo-glossary/terms/final_product_version"},{"id":"terms/geocoding","title":"Geocoding","description":"Translation of one form of Location into another.","permalink":"/eo-glossary/terms/geocoding"},{"id":"terms/geographic_coordinate_reference_system","title":"Geographic Coordinate Reference System","description":"Coordinate Reference System (CRS) that has a geodetic Reference frame and an ellipsoidal coordinate system.","permalink":"/eo-glossary/terms/geographic_coordinate_reference_system"},{"id":"terms/geographic_data","title":"Geographic Data","description":"Data with implicit or explicit reference to a Location relative to the Earth.","permalink":"/eo-glossary/terms/geographic_data"},{"id":"terms/geographic_grid","title":"Geographic Grid","description":"Regular grid based on a Geographic Coordinate Reference System (CRS).","permalink":"/eo-glossary/terms/geographic_grid"},{"id":"terms/geographic_identifier","title":"Geographic Identifier","description":"Spatial reference in the form of a label or code that identifies a Location.","permalink":"/eo-glossary/terms/geographic_identifier"},{"id":"terms/geolocating","title":"Geolocating","description":"Geopositioning of an Object using a Physical Sensor Model or a True Replacement Model.","permalink":"/eo-glossary/terms/geolocating"},{"id":"terms/geospatial_data","title":"Geospatial Data","description":"Data consisting of, derived from, or relating to information that is directly linked to specific geographical locations.","permalink":"/eo-glossary/terms/geospatial_data"},{"id":"terms/geosphere","title":"Geosphere","description":"The masses of minerals that constitute planet Earth.","permalink":"/eo-glossary/terms/geosphere"},{"id":"terms/granule","title":"Granule","description":"The smallest aggregation of data which is independently managed (i.e. described, inventoried, retrievable).","permalink":"/eo-glossary/terms/granule"},{"id":"terms/grid","title":"Grid","description":"Network composed of two or more sets of curves in which the members of each set intersect the members of the other sets in an algorithmic way.","permalink":"/eo-glossary/terms/grid"},{"id":"terms/hydrosphere","title":"Hydrosphere","description":"The masses of liquid water, such as oceans, lakes, and rivers.","permalink":"/eo-glossary/terms/hydrosphere"},{"id":"terms/information","title":"Information","description":"The result of organisation, interpretation, categorisation, classification, or some other form of processing of Data attaching to it a certain meaning that can be understood by the addressee.","permalink":"/eo-glossary/terms/information"},{"id":"terms/instrument_data","title":"Instrument Data","description":"Data specifically associated with the instrument, either because it was generated by the instrument or included in data packets identified with that instrument.","permalink":"/eo-glossary/terms/instrument_data"},{"id":"terms/lead_time","title":"Lead Time","description":"Minimum time of interval between an Observation being tasked and being performed.","permalink":"/eo-glossary/terms/lead_time"},{"id":"terms/lithosphere","title":"Lithosphere","description":"The solid, inanimate outer layer of the Geosphere. For the purposes of Earth Observation, includes soils (\'pedosphere\').","permalink":"/eo-glossary/terms/lithosphere"},{"id":"terms/location","title":"Location","description":"Particular Place referenced by an identifier.","permalink":"/eo-glossary/terms/location"},{"id":"terms/location_error","title":"Location Error","description":"Measure of the agreement between the represented Location of an Object and the true Location.","permalink":"/eo-glossary/terms/location_error"},{"id":"terms/long_term_preservation","title":"Long Term Preservation","description":"The act of maintaining information in a correct and independently understandable form over the long term.","permalink":"/eo-glossary/terms/long_term_preservation"},{"id":"terms/measurand","title":"Measurand","description":"Particular Quantity subject to Measurement.","permalink":"/eo-glossary/terms/measurand"},{"id":"terms/metadata","title":"Metadata","description":"Data describing other data, providing an understanding of the content and utility of a product or collection.","permalink":"/eo-glossary/terms/metadata"},{"id":"terms/minimum_mapping_unit","title":"Minimum Mapping Unit","description":"The area of the smallest Feature that is still represented on a map.","permalink":"/eo-glossary/terms/minimum_mapping_unit"},{"id":"terms/minimum_mapping_width","title":"Minimum Mapping Width","description":"The width of the smallest linear Feature that is still represented on a map.","permalink":"/eo-glossary/terms/minimum_mapping_width"},{"id":"terms/object","title":"Object","description":"Entity with a well-defined boundary and identity that encapsulates state and behaviour.","permalink":"/eo-glossary/terms/object"},{"id":"terms/obsolete_product_or_collection","title":"Obsolete Product or Collection","description":"Products or collections which have been superseded by later versions of a product or collection.","permalink":"/eo-glossary/terms/obsolete_product_or_collection"},{"id":"terms/path","title":"Path","description":"Line defined in an algorithmic way using at least two positions (can be open-ended). Alternative: line connecting two positions in an algorithmic way (limited by end points).","permalink":"/eo-glossary/terms/path"},{"id":"terms/period","title":"Period","description":"Particular era or span of time.","permalink":"/eo-glossary/terms/period"},{"id":"terms/period_identifier","title":"Period Identifier","description":"Temporal reference in the form of a label or code that identifies a Period.","permalink":"/eo-glossary/terms/period_identifier"},{"id":"terms/phenomenon","title":"Phenomenon","description":"Entity with at least one Property referenced by an identifier.","permalink":"/eo-glossary/terms/phenomenon"},{"id":"terms/place","title":"Place","description":"Part of any space referenced by an identifier.","permalink":"/eo-glossary/terms/place"},{"id":"terms/preservation","title":"Preservation","description":"Processes and operations used to ensure data technical and intellectual survival through time.","permalink":"/eo-glossary/terms/preservation"},{"id":"terms/process","title":"Process","description":"Series of activities that interact to produce a result.","permalink":"/eo-glossary/terms/process"},{"id":"terms/product","title":"Product","description":"Electronic data package distributable to users; content is derived from instrument data via processing involving ancillary and auxiliary data.","permalink":"/eo-glossary/terms/product"},{"id":"terms/provisional_product","title":"Provisional Product","description":"Products in a research and development phase not yet published into a standardized collection.","permalink":"/eo-glossary/terms/provisional_product"},{"id":"terms/quality_indicator","title":"Quality Indicator","description":"Indicator providing sufficient information to allow all users to readily evaluate the fitness for purpose of the data or derived product.","permalink":"/eo-glossary/terms/quality_indicator"},{"id":"terms/quantity","title":"Quantity","description":"Property having a magnitude that can be expressed as a number from a continuous and contiguous range and a reference.","permalink":"/eo-glossary/terms/quantity"},{"id":"terms/replicability","title":"Replicability","description":"Property enabling other researchers to conduct an independent study with different data and similar but not identical methods, yet arriving at results that confirm the original study\'s hypothesis.","permalink":"/eo-glossary/terms/replicability"},{"id":"terms/representativeness","title":"Representativeness","description":"Quality or characteristic of a measurement or observation to accurately represent a specific geographic location, time period, or environmental condition.","permalink":"/eo-glossary/terms/representativeness"},{"id":"terms/reproducibility","title":"Reproducibility","description":"Concerned with the validity of the results of a particular study, enabling readers to check whether results have been manipulated by reproducing exactly the same study using the same data and methods.","permalink":"/eo-glossary/terms/reproducibility"},{"id":"terms/sensor","title":"Sensor","description":"Device or instrument suited (through physical/chemical interaction) to measure one or more properties of a Phenomenon and thus collect factual/objective data.","permalink":"/eo-glossary/terms/sensor"},{"id":"terms/source_data","title":"Source Data","description":"Data required for production of an EO Collection (e.g., unenhanced satellite mission data) as well as further processed Level-1 data, or any other pre-processed format meeting program requirements.","permalink":"/eo-glossary/terms/source_data"},{"id":"terms/spatial_completeness","title":"Spatial Completeness","description":"Presence or absence of gaps, which are missing values in an otherwise continuous spatial data series.","permalink":"/eo-glossary/terms/spatial_completeness"},{"id":"terms/spatial_consistency","title":"Spatial Consistency","description":"Condition where the spatial statistical properties of the data depend only on the underlying physical processes and not on other factors such as fusing different products or sensors.","permalink":"/eo-glossary/terms/spatial_consistency"},{"id":"terms/spatial_extent","title":"Spatial Extent","description":"Zone or region of space described by a geographic identifier in the form of a label or code, or by a bounding box, representing the maximum spatial boundary within which the user is requesting data.","permalink":"/eo-glossary/terms/spatial_extent"},{"id":"terms/spatial_reporting_unit","title":"Spatial Reporting Unit","description":"Smallest spatial object of interest that may be used for reporting and for which the information should be aggregated.","permalink":"/eo-glossary/terms/spatial_reporting_unit"},{"id":"terms/spectral_band","title":"Spectral Band","description":"Part of the electromagnetic spectrum of specific wavelengths, in remote sensing usually described by central wavelength and bandwidth.","permalink":"/eo-glossary/terms/spectral_band"},{"id":"terms/spectral_resolution","title":"Spectral Resolution","description":"Measure of the ability to resolve features in the electromagnetic spectrum.","permalink":"/eo-glossary/terms/spectral_resolution"},{"id":"terms/stability","title":"Stability","description":"Maximum acceptable change in Uncertainty per decade.","permalink":"/eo-glossary/terms/stability"},{"id":"terms/standard_uncertainty","title":"Standard Uncertainty","description":"Standard deviation of the probability distribution describing the spread of possible values in quantitative/continuous data.","permalink":"/eo-glossary/terms/standard_uncertainty"},{"id":"terms/temporal_consistency","title":"Temporal Consistency","description":"Condition where the temporal statistical properties of the sample depend only on the underlying physical processes and not on other factors such as fusing different products or sensors.","permalink":"/eo-glossary/terms/temporal_consistency"},{"id":"terms/temporal_extent","title":"Temporal Extent","description":"Period during which data was collected, observations were made, or for which the model was run.","permalink":"/eo-glossary/terms/temporal_extent"},{"id":"terms/temporal_reporting_period","title":"Temporal Reporting Period","description":"Time period used for reporting and for which the information should be aggregated from the native temporal resolution.","permalink":"/eo-glossary/terms/temporal_reporting_period"},{"id":"terms/temporal_resolution","title":"Temporal Resolution","description":"Observation or model output representing regular intervals, specifying the length of the interval that determines the smallest event or process that can be resolved.","permalink":"/eo-glossary/terms/temporal_resolution"},{"id":"terms/thematic_resolution","title":"Thematic Resolution","description":"Level of categorical detail of information expressed by the number of classes.","permalink":"/eo-glossary/terms/thematic_resolution"},{"id":"terms/time_of_day","title":"Time of Day","description":"Time of the day at which the variable or parameter is observed or simulated by a model.","permalink":"/eo-glossary/terms/time_of_day"},{"id":"terms/time_of_year","title":"Time of Year","description":"Time of the year at which the variable is observed or simulated by a model.","permalink":"/eo-glossary/terms/time_of_year"},{"id":"terms/timeliness","title":"Timeliness","description":"Period between the moment of requesting information and the moment of availability of information.","permalink":"/eo-glossary/terms/timeliness"},{"id":"terms/traceability","title":"Traceability","description":"Property of a measurement result whereby the result can be related to a reference through a documented unbroken chain of calibrations each contributing to the measurement uncertainty.","permalink":"/eo-glossary/terms/traceability"},{"id":"terms/trait","title":"Trait","description":"Characteristic belonging to an entity and referenced by an identifier.","permalink":"/eo-glossary/terms/trait"},{"id":"terms/uncertainty","title":"Uncertainty","description":"Parameter, associated with the result of a measurement, that characterises the dispersion of the values that could reasonably be attributed to the measurand.","permalink":"/eo-glossary/terms/uncertainty"},{"id":"terms/update_frequency","title":"Update Frequency","description":"Frequency at which the product is available to users.","permalink":"/eo-glossary/terms/update_frequency"},{"id":"terms/user","title":"User","description":"Entity (person, organization, institution, etc.) that is requesting data or information with certain characteristics described by needs and/or requirements.","permalink":"/eo-glossary/terms/user"},{"id":"terms/user_interface","title":"User Interface","description":"Set of all the components of an interactive system that provide information and controls for the user to accomplish specific tasks with the interactive system.","permalink":"/eo-glossary/terms/user_interface"},{"id":"terms/validation","title":"Validation","description":"Process of assessing, by independent means, the quality of the data products derived from the system outputs.","permalink":"/eo-glossary/terms/validation"},{"id":"terms/value","title":"Value","description":"Element of a type domain.","permalink":"/eo-glossary/terms/value"},{"id":"terms/verification","title":"Verification","description":"Provision of objective evidence that a given item fulfils specified requirements.","permalink":"/eo-glossary/terms/verification"},{"id":"terms/version_control","title":"Version Control","description":"Method of working with collections, similar to version control systems used in traditional software development but optimized to allow better processing of data and collaboration in data analytics and research contexts.","permalink":"/eo-glossary/terms/version_control"},{"id":"terms/vertical_levels","title":"Vertical Levels","description":"Levels of a vertical discretization, e.g. pressure levels in an atmospheric model reanalysis or height levels in a forest biomass EO product.","permalink":"/eo-glossary/terms/vertical_levels"}],"unlisted":false}}')}}]);